#include <vector>
#include <iostream>
#include <algorithm>

using namespace std;

typedef long long ll;

// Modulo constant
const ll MOD = 1e9 + 7;
const int MAX_N = 100005;

ll fact[MAX_N];
ll invFact[MAX_N];

// Modular exponentiation: (base^exp) % MOD
ll power(ll base, ll exp) {
    ll res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

// Modular inverse using Fermat's Little Theorem
ll modInverse(ll n) {
    return power(n, MOD - 2);
}

// Precompute factorials and inverse factorials
void precompute_factorials(int max_val) {
    fact[0] = 1;
    for (int i = 1; i <= max_val; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }

    invFact[max_val] = modInverse(fact[max_val]);
    for (int i = max_val - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
    }
}

// Combination nCk % MOD
ll nCr(int n, int r) {
    if (r < 0 || r > n) return 0;
    if (r == 0 || r == n) return 1;
    if (r > n / 2) r = n - r;

    ll numerator = fact[n];
    ll denominator = (invFact[r] * invFact[n - r]) % MOD;
    return (numerator * denominator) % MOD;
}

// The required function signature uses Int64, which maps to ll in C++
ll solve(ll n, ll pos, ll k) {
    // We need to precompute factorials up to N-1, which is at most 10^5 - 1.
    // Since N <= 10^5, we use MAX_N = 100005.
    if (fact[0] == 0) {
        precompute_factorials(MAX_N - 1);
    }

    // L: Number of people to the left (indices 0 to pos-1)
    ll L = pos;
    // R: Number of people to the right (indices pos+1 to n-1)
    ll R = n - 1 - pos;

    ll total_ways_visible = 0;

    // Iterate over k_L, the number of visible people from the left.
    // 0 <= k_L <= L
    // k_R = K - k_L. We need 0 <= k_R <= R.
    // k_R >= 0  => K - k_L >= 0 => k_L <= K
    // k_R <= R  => K - k_L <= R => k_L >= K - R

    ll k_L_min = max(0LL, k - R);
    ll k_L_max = min(k, L);

    for (ll k_L = k_L_min; k_L <= k_L_max; ++k_L) {
        ll k_R = k - k_L;

        // Number of ways to choose k_L people from L to see: C(L, k_L)
        ll ways_L = nCr(L, k_L);

        // Number of ways to choose k_R people from R to see: C(R, k_R)
        ll ways_R = nCr(R, k_R);

        ll current_ways = (ways_L * ways_R) % MOD;

        total_ways_visible = (total_ways_visible + current_ways) % MOD;
    }

    // The person at pos can choose 'L' or 'R' (2 options), independent of K.
    // Total ways = 2 * total_ways_visible
    ll final_answer = (2 * total_ways_visible) % MOD;

    return final_answer;
}
