import java.util.*;
import java.math.BigInteger;

public class Solution {
    private static final long MOD = 1_000_000_007L;
    private static final int MAX_N = 100005;
    private static long[] fact = new long[MAX_N];

    // Modular exponentiation: (base^exp) % mod
    private static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }

    // Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
    private static long modInverse(long n) {
        return power(n, MOD - 2);
    }

    // Precompute factorials
    private static void precomputeFactorials() {
        fact[0] = 1;
        for (int i = 1; i < MAX_N; i++) {
            fact[i] = (fact[i - 1] * i) % MOD;
        }
    }

    // Combinations: nCk % MOD
    private static long nCr(int n, int r) {
        if (r < 0 || r > n) {
            return 0;
        }
        if (r == 0 || r == n) {
            return 1;
        }
        if (r > n / 2) {
            r = n - r;
        }

        // nCr = n! / (r! * (n-r)!)
        long numerator = fact[n];
        long denominator = (fact[r] * fact[n - r]) % MOD;

        return (numerator * modInverse(denominator)) % MOD;
    }

    // Static initializer to run precomputation once
    static {
        precomputeFactorials();
    }

    /**
     * Returns the possible direction assignment count.
     * @param n Total number of people.
     * @param pos Index of the person observing.
     * @param k Target number of visible people.
     * @return The number of ways modulo 10^9 + 7.
     */
    public static long solve(long n, long pos, long k) {
        if (n == 1) {
            // If N=1, pos=0. K must be 0. Person 0 has 2 choices.
            return 2;
        }

        // We need to calculate C(N-1, K)
        // N-1 is the total number of people other than the observer.
        int N_eff = (int) (n - 1);
        int K_int = (int) k;

        long combinations = nCr(N_eff, K_int);

        // Total ways = 2 * C(N-1, K)
        // Factor of 2 comes from the observer (person at pos) choosing 'L' or 'R'.
        long result = (2 * combinations) % MOD;

        return result;
    }
}

