	}

    // Maximum value we need factorials up to is N-1
    maxN := n - 1
    if maxN < 0 {
        // Should not happen given constraints 1 <= n
        return 0
    }

    // Precompute factorials needed for combinations up to N-1
	precomputeFactorials(maxN)

	// The number of ways to select K visible people from N-1 total non-pos people 
    // is given by Vandermonde's Identity: C(pos + (N-1-pos), K) = C(N-1, K).
	waysNonPos := combinations(n-1, k)

	// The person at pos has 2 independent choices ('L' or 'R'), which multiplies the count.
	result := (waysNonPos * 2) % MOD

	return result
}
